import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useToast } from '../../context/ToastContext';

const Logo = () => (
  <div style={{display:'flex',alignItems:'center',gap:12,justifyContent:'center',marginBottom:24}}>
    <div style={{width:42,height:42,background:'linear-gradient(135deg,#6366f1,#8b5cf6)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',boxShadow:'0 6px 20px rgba(99,102,241,.5)'}}>
      <span style={{color:'#fff',fontFamily:'var(--ff-h)',fontWeight:800,fontSize:21}}>D</span>
    </div>
    <span style={{fontFamily:'var(--ff-h)',fontWeight:800,fontSize:22,letterSpacing:'-0.03em'}}>DeLaxiY</span>
  </div>
);

// ── Validators ───────────────────────────────────────────────────────────────
function vName(v) {
  if (!v.trim())                     return 'Please fill the field';
  if (v.trim().length < 2)           return 'Name must be at least 2 characters';
  if (/\d/.test(v))                  return 'Name cannot contain numbers';
  if (/[^a-zA-Z\s-]/.test(v))       return 'Name can only contain letters';
  return '';
}
function vEmail(v) {
  if (!v.trim())                     return 'Please fill the field';
  if (!v.includes('@'))              return 'Email must contain @';
  const parts = v.split('@');
  if (parts.length !== 2 || !parts[1]) return 'Enter a valid email';
  if (!parts[1].includes('.'))       return 'Email domain must contain a dot (e.g. @gmail.com)';
  if (!/^[^@]+@[^@]+\.[^@]{2,}$/.test(v.trim())) return 'Enter a valid email (e.g. name@gmail.com)';
  return '';
}
function vPw(v) {
  if (!v)                            return 'Please fill the field';
  if (v.length < 6)                  return 'Password must be at least 6 characters';
  if (!/[A-Z]/.test(v))             return 'Must contain at least 1 uppercase letter (A-Z)';
  if (!/[0-9]/.test(v))             return 'Must contain at least 1 number (0-9)';
  if (!/[!@#$%^&*()_+={}|,.<>?/-]/.test(v)) return 'Must contain at least 1 special character (!@#$...)';
  return '';
}
function vCfm(v, pw) {
  if (!v)           return 'Please fill the field';
  if (v !== pw)     return 'Passwords do not match';
  return '';
}

// ── Strength calculator ──────────────────────────────────────────────────────
function getStrength(pw) {
  if (!pw) return 0;
  let score = 0;
  if (pw.length >= 6)  score++;
  if (pw.length >= 10) score++;
  if (/[A-Z]/.test(pw) && /[a-z]/.test(pw)) score++;
  if (/[0-9]/.test(pw)) score++;
  if (/[!@#$%^&*()_+={}|,.<>?/-]/.test(pw)) score++;
  return Math.min(4, score);
}

export default function AuthModal({ mode, onClose, onSwitch }) {
  const { login, register, loading } = useAuth();
  const { add }  = useToast();
  const navigate = useNavigate();

  // ── Fully controlled state — onChange updates both value and validation ──
  const [name,    setName]    = useState('');
  const [email,   setEmail]   = useState('');
  const [pw,      setPw]      = useState('');
  const [cfm,     setCfm]     = useState('');

  // Error state — only shown after user has touched field
  const [touched, setTouched] = useState({});
  const [errs,    setErrs]    = useState({});
  const [apiErr,  setApiErr]  = useState('');
  const [show,    setShow]    = useState(false);
  const [showC,   setShowC]   = useState(false);

  const strength = getStrength(pw);
  const sColor   = ['transparent','#f43f5e','#f59e0b','#06b6d4','#10b981'][strength];
  const sLabel   = ['','Weak','Fair','Good','Strong'][strength];

  // ── Handlers — validate on every keystroke but only show after touch ──────
  function handleName(e) {
    const v = e.target.value;
    setName(v);
    setTouched(p => ({...p, name: true}));
    setErrs(p => ({...p, name: vName(v)}));
  }
  function handleEmail(e) {
    const v = e.target.value;
    setEmail(v);
    setTouched(p => ({...p, email: true}));
    setErrs(p => ({...p, email: vEmail(v)}));
  }
  function handlePw(e) {
    const v = e.target.value;
    setPw(v);
    setTouched(p => ({...p, pw: true}));
    setErrs(p => ({
      ...p,
      pw: vPw(v),
      cfm: touched.cfm ? vCfm(cfm, v) : p.cfm,
    }));
  }
  function handleCfm(e) {
    const v = e.target.value;
    setCfm(v);
    setTouched(p => ({...p, cfm: true}));
    setErrs(p => ({...p, cfm: vCfm(v, pw)}));
  }

  // ── Submit ────────────────────────────────────────────────────────────────
  async function submit(e) {
    e.preventDefault();
    // Touch all fields to show errors
    setTouched({name:true, email:true, pw:true, cfm:true});
    const ev = {};
    if (mode === 'register') { const n = vName(name);    if (n) ev.name = n; }
    const em = vEmail(email);                             if (em) ev.email = em;
    const pe = vPw(pw);                                   if (pe) ev.pw = pe;
    if (mode === 'register') { const c = vCfm(cfm, pw);  if (c) ev.cfm = c; }
    if (Object.keys(ev).length) { setErrs(ev); return; }
    setApiErr('');
    try {
      if (mode === 'login') await login(email, pw);
      else                  await register(name, email, pw);
      add(mode === 'login' ? '🎉 Welcome back!' : '🚀 Account created!', 'success');
      onClose();
      navigate('/dashboard');
    } catch(err) { setApiErr(err.message); }
  }

  // ── Styles ────────────────────────────────────────────────────────────────
  const IS = (key) => {
    const hasErr = touched[key] && errs[key];
    const isOk   = touched[key] && !errs[key] && (key==='name'?name:key==='email'?email:key==='pw'?pw:cfm);
    return {
      background: '#fff',
      border: `1.5px solid ${hasErr ? '#f43f5e' : isOk ? '#10b981' : '#cbd5e1'}`,
      borderRadius: '10px',
      padding: '11px 15px',
      color: '#1e293b',
      fontFamily: 'inherit',
      fontSize: '14px',
      width: '100%',
      outline: 'none',
      boxSizing: 'border-box',
      transition: 'border-color .15s',
    };
  };

  const onF  = e => { e.target.style.borderColor = '#6366f1'; e.target.style.boxShadow = '0 0 0 3px rgba(99,102,241,.15)'; };
  const onBl = e => { e.target.style.boxShadow = 'none'; };

  // ── Field wrapper ─────────────────────────────────────────────────────────
  const F = ({ id, label, errKey, okMsg, children }) => {
    const err = touched[errKey] && errs[errKey];
    const ok  = touched[errKey] && !errs[errKey] && okMsg;
    return (
      <div style={{display:'flex',flexDirection:'column',gap:5}}>
        <label htmlFor={id} style={{fontSize:'11px',fontWeight:700,color:'#64748b',textTransform:'uppercase',letterSpacing:'.05em'}}>
          {label}
        </label>
        {children}
        {err
          ? <span style={{fontSize:'12px',color:'#f43f5e',display:'flex',alignItems:'center',gap:4,fontWeight:500,lineHeight:1.4}}>
              <span style={{fontSize:9,flexShrink:0}}>●</span> {err}
            </span>
          : ok
          ? <span style={{fontSize:'12px',color:'#10b981',display:'flex',alignItems:'center',gap:4}}>
              <span>✓</span> {okMsg}
            </span>
          : null
        }
      </div>
    );
  };

  return (
    <div className="overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal modal-sm scale-in" onClick={e => e.stopPropagation()}>
        <div style={{height:4,background:'linear-gradient(90deg,#6366f1,#8b5cf6)',borderRadius:'20px 20px 0 0'}}/>
        <div style={{padding:'30px 32px 24px'}}>
          <Logo />

          <div style={{textAlign:'center',marginBottom:22}}>
            <h2 style={{fontSize:20,marginBottom:5,color:'#1e293b'}}>{mode==='login'?'Welcome back':'Create account'}</h2>
            <p style={{fontSize:13,color:'#64748b'}}>{mode==='login'?'Sign in to your DeLaxiY account':'Start managing orders and dashboards'}</p>
          </div>

          {apiErr && (
            <div style={{background:'#fef2f2',border:'1px solid #fecaca',borderRadius:'10px',padding:'10px 14px',color:'#f43f5e',fontSize:13,marginBottom:14,display:'flex',alignItems:'center',gap:8}}>
              <span>✕</span> {apiErr}
            </div>
          )}

          <form onSubmit={submit} style={{display:'flex',flexDirection:'column',gap:14}} noValidate>

            {/* Full Name */}
            {mode === 'register' && (
              <F id="am-name" label="Full Name" errKey="name" okMsg="Looks good!">
                <input id="am-name" type="text" name="fullname"
                  placeholder="Enter your full name"
                  value={name}
                  onChange={handleName}
                  onFocus={onF} onBlur={onBl}
                  autoComplete="name"
                  style={IS('name')}
                />
              </F>
            )}

            {/* Email */}
            <F id="am-email" label="Email Address" errKey="email" okMsg="Valid email ✓">
              <input id="am-email" type="text" name="email"
                placeholder="you@example.com"
                value={email}
                onChange={handleEmail}
                onFocus={onF} onBlur={onBl}
                autoComplete="email"
                style={IS('email')}
              />
            </F>

            {/* Password */}
            <F id="am-pwd" label="Password" errKey="pw">
              <div style={{position:'relative'}}>
                <input id="am-pwd" name="password"
                  type={show ? 'text' : 'password'}
                  placeholder="Min 6 chars, 1 uppercase, 1 number, 1 special"
                  value={pw}
                  onChange={handlePw}
                  onFocus={onF} onBlur={onBl}
                  autoComplete={mode==='login'?'current-password':'new-password'}
                  style={{...IS('pw'), paddingRight:44}}
                />
                <button type="button" onClick={() => setShow(s=>!s)}
                  style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'#94a3b8',cursor:'pointer',fontSize:15,padding:2,lineHeight:1}}>
                  {show ? '🙈' : '👁'}
                </button>
              </div>
              {/* Password requirements hint */}
              {mode === 'register' && touched.pw && (
                <div style={{fontSize:11,color:'#64748b',marginTop:5,lineHeight:1.7}}>
                  {[
                    {ok: pw.length >= 6,                                                    msg: '6+ characters'},
                    {ok: /[A-Z]/.test(pw),                                                  msg: '1 uppercase (A-Z)'},
                    {ok: /[0-9]/.test(pw),                                                  msg: '1 number (0-9)'},
                    {ok: /[!@#$%^&*()_+={}|,.<>?/-]/.test(pw),                           msg: '1 special char (!@#$)'},
                  ].map((r,i) => (
                    <div key={i} style={{display:'flex',alignItems:'center',gap:5,color:r.ok?'#10b981':'#94a3b8'}}>
                      <span style={{fontSize:10}}>{r.ok ? '✓' : '○'}</span> {r.msg}
                    </div>
                  ))}
                </div>
              )}
              {/* Strength bar */}
              {mode === 'register' && pw.length > 0 && (
                <div style={{marginTop:6}}>
                  <div style={{display:'flex',gap:4}}>
                    {[1,2,3,4].map(i=>(
                      <div key={i} style={{flex:1,height:3,borderRadius:99,background:i<=strength?sColor:'#e2e8f0',transition:'background .3s'}}/>
                    ))}
                  </div>
                  <span style={{fontSize:11,color:sColor,fontWeight:600,marginTop:3,display:'block'}}>{sLabel}</span>
                </div>
              )}
            </F>

            {/* Confirm Password */}
            {mode === 'register' && (
              <F id="am-conf" label="Confirm Password" errKey="cfm" okMsg="Passwords match ✓">
                <div style={{position:'relative'}}>
                  <input id="am-conf" name="confirmPassword"
                    type={showC ? 'text' : 'password'}
                    placeholder="Repeat your password"
                    value={cfm}
                    onChange={handleCfm}
                    onFocus={onF} onBlur={onBl}
                    autoComplete="new-password"
                    style={{...IS('cfm'), paddingRight:44}}
                  />
                  <button type="button" onClick={() => setShowC(s=>!s)}
                    style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'#94a3b8',cursor:'pointer',fontSize:15,padding:2,lineHeight:1}}>
                    {showC ? '🙈' : '👁'}
                  </button>
                </div>
              </F>
            )}

            {/* Submit */}
            <button type="submit" disabled={loading}
              style={{display:'flex',alignItems:'center',justifyContent:'center',gap:8,width:'100%',padding:'13px',marginTop:4,fontSize:15,fontWeight:700,fontFamily:'inherit',background:'linear-gradient(135deg,#6366f1,#8b5cf6)',color:'#fff',border:'none',borderRadius:'10px',cursor:loading?'not-allowed':'pointer',boxShadow:'0 4px 16px rgba(99,102,241,.4)',opacity:loading?.7:1,transition:'opacity .2s'}}>
              {loading
                ? <><span className="spinner" style={{borderTopColor:'#fff',width:14,height:14}}/>{mode==='login'?' Signing in…':' Creating account…'}</>
                : mode==='login' ? '→ Sign In' : '→ Create Account'
              }
            </button>
          </form>

          <div style={{textAlign:'center',marginTop:18,fontSize:13,color:'#64748b'}}>
            {mode==='login'
              ? <>Don't have an account?{' '}<button type="button" onClick={()=>onSwitch('register')} style={{background:'none',border:'none',color:'#6366f1',cursor:'pointer',fontWeight:700,fontSize:13}}>Register free</button></>
              : <>Already have an account?{' '}<button type="button" onClick={()=>onSwitch('login')} style={{background:'none',border:'none',color:'#6366f1',cursor:'pointer',fontWeight:700,fontSize:13}}>Sign in</button></>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
